return [{ json: { project_id, fields } }];

const meta = $input.first().json[0] || $input.first().json;
const prevVersion = $('Parse Prompt Revert Body').first().json.version;
return [{ json: { ...meta, target_version: prevVersion } }];

const historical = $input.first().json[0] || $input.first().json;
const meta = $('Extract Meta').first().json;

// Get current max version
const currentMaxResp = await $('Fetch Current Max Version').first();

return [{ json: {
  project_id: meta.project_id,
  prompt_type: meta.prompt_type,
  prompt_text: historical.prompt_text,
  prompt_id: $('Parse Prompt Revert Body').first().json.prompt_id
} }];

const active = $input.first().json[0] || $input.first().json;
const revertData = $('Prepare Revert Data').first().json;
return [{ json: {
  active_id: active.id,
  new_version: (active.version || 1) + 1,
  project_id: revertData.project_id,
  prompt_type: revertData.prompt_type,
  prompt_text: revertData.prompt_text
} }];

